#include<bits/stdc++.h>
using namespace std;
long long m=1e9+7,n;
struct matrix
{
    long long a[4][4];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=1;i<=3;i++)
        {
            for(long long j=1;j<=3;j++)
            {
                for(long long k=1;k<=3;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%m)*(b.a[k][j]%m)%m;
                    c.a[i][j]%=m;
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    for(long long i=1;i<=2;i++)
    {
        ans.a[i][i]=1;
    }
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d",&n);
        if(n<=3)
        {
            printf("1\n");
            continue;
        }
        base=ans=matrix();
        base.a[1][1]=base.a[1][3]=base.a[2][1]=base.a[3][2]=1;
        fastpow(n-3);
        printf("%lld\n",(ans.a[1][1]+ans.a[1][2]+ans.a[1][3])%m);
    }
    return 0;
}
